package com.hospital.management.controller.schedule;import com.hospital.management.model.*;import javax.servlet.http.*;final class ScheduleRequest{private ScheduleRequest(){}static Long id(String v){try{long x=Long.parseLong(v);return x>0?x:null;}catch(Exception e){return null;}}static DoctorScheduleForm form(HttpServletRequest q,Long id){DoctorScheduleForm f=new DoctorScheduleForm();f.setScheduleId(id);f.setDoctorId(id(q.getParameter("doctorId")));f.setDayOfWeek(q.getParameter("dayOfWeek"));f.setStartTime(q.getParameter("startTime"));f.setEndTime(q.getParameter("endTime"));f.setSlotDurationMinutes(q.getParameter("slotDurationMinutes"));f.setAvailable("true".equals(q.getParameter("available")));return f;}static DoctorScheduleForm form(DoctorSchedule s){DoctorScheduleForm f=new DoctorScheduleForm();f.setScheduleId(s.getScheduleId());f.setDoctorId(s.getDoctorId());f.setDayOfWeek(s.getDayOfWeek());f.setStartTime(s.getStartTime().toString());f.setEndTime(s.getEndTime().toString());f.setSlotDurationMinutes(String.valueOf(s.getSlotDurationMinutes()));f.setAvailable(s.isAvailable());return f;}static AuthenticatedUser user(HttpServletRequest q){if(q==null)return null;HttpSession session=q.getSession(false);if(session==null)return null;Object value=session.getAttribute("authenticatedUser");return value instanceof AuthenticatedUser?(AuthenticatedUser)value:null;}}
